inline int BandIO_initialize(__private BandWriterInt *writer,
                             const int imageSizeX, const int imageSizeY,
                             const int firstX, const int firstY,
                             const int checked)
{
    int columnOffset = firstX / 2;
    int verticalStride;

    if (firstX & 1) {
        verticalStride = imageSizeX / 2;
        columnOffset += divRndUpInt(imageSizeX, 2) * divRndUpInt(imageSizeY, 2);
        writer->strideLowToHigh = (imageSizeX * imageSizeY) / 2;
    } else {
        verticalStride = imageSizeX / 2 + (imageSizeX & 1);
        writer->strideLowToHigh = divRndUpInt(imageSizeY, 2) * imageSizeX;
    }

    writer->strideHighToLow = verticalStride - writer->strideLowToHigh;

    if (checked) {
        writer->end = columnOffset
                    + (imageSizeY / 2) * verticalStride
                    + (imageSizeY & 1) * writer->strideLowToHigh;
    } else {
        writer->end = 0;
    }

    return columnOffset
         + (firstY / 2) * verticalStride
         + (firstY & 1) * writer->strideLowToHigh;
}

