        column->pixel2 = PixelLoader_loadFrom(&column->loader, input, checkedLoads);
        column->pixel1 = PixelLoader_loadFrom(&column->loader, input, checkedLoads);
        column->pixel0 = PixelLoader_loadFrom(&column->loader, input, checkedLoads);
        PixelLoader_init(&column->loader, sizeX, sizeY, firstX, firstY + 1, checkedLoads);
    } else {
        PixelLoader_init(&column->loader, sizeX, sizeY, firstX, firstY - 2, checkedLoads);
        column->pixel0 = PixelLoader_loadFrom(&column->loader, input, checkedLoads);
        column->pixel1 = PixelLoader_loadFrom(&column->loader, input, checkedLoads);
        column->pixel2 = PixelLoader_loadFrom(&column->loader, input, checkedLoads);
