inline void loadAndVerticallyTransform53(__private FDWT53ColumnInt *column,
                                         __global const int *input,
                                         __local int *buffer,
                                         const int verticalStride,
                                         const int winSY,
                                         const int checkedLoads)
{
    buffer[column->offset + 0 * verticalStride] = column->pixel0;
    buffer[column->offset + 1 * verticalStride] = column->pixel1;
    buffer[column->offset + 2 * verticalStride] = column->pixel2;

    for (int i = 3; i < (3 + winSY); i++) {
        buffer[column->offset + i * verticalStride] =
            PixelLoader_loadFrom(&column->loader, input, checkedLoads);
    }

    column->pixel0 = buffer[column->offset + (winSY + 0) * verticalStride];
    column->pixel1 = buffer[column->offset + (winSY + 1) * verticalStride];
    column->pixel2 = buffer[column->offset + (winSY + 2) * verticalStride];

    TB_forEachVerticalOdd(buffer, column->offset, verticalStride, winSY + 3);
    TB_forEachVerticalEven(buffer, column->offset, verticalStride, winSY + 3);
