    if (tid < 3) {
        const int colId = tid + ((tid == 0) ? WIN_SX : -3);
        initColumn53(&boundaryColumn, input, sizeX, sizeY, colId, firstY,
                     checkedLoads, groupX, groupY, WIN_SX, oddOffset);
    }

    const int outColumnIndex = parityIdxRuntime(tid, WIN_SX);
    const int outColumnOffset = TB_getColumnOffset(outColumnIndex, oddOffset);
    const int outputFirstX = groupX * WIN_SX + outColumnIndex;

    BandWriterInt writer;
    BandWriter_init(&writer, sizeX, sizeY, outputFirstX, firstY, checkedWrites);

    for (int w = 0; w < winSteps; w++) {
        loadAndVerticallyTransform53(&column, input, buffer, verticalStride, WIN_SY, checkedLoads);
        if (tid < 3) {
            loadAndVerticallyTransform53(&boundaryColumn, input, buffer, verticalStride, WIN_SY, checkedLoads);
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        TB_forEachHorizontalOdd(buffer, 2, WIN_SY, verticalStride, oddOffset, WIN_SX);

        barrier(CLK_LOCAL_MEM_FENCE);

        TB_forEachHorizontalEven(buffer, 2, WIN_SY, verticalStride, oddOffset, WIN_SX);

        barrier(CLK_LOCAL_MEM_FENCE);

        for (int r = 2; r < (2 + WIN_SY); r += 2) {
            BandWriter_writeLowInto(&writer, output,
                                    buffer[outColumnOffset + r * verticalStride],
                                    checkedWrites);
            BandWriter_writeHighInto(&writer, output,
                                     buffer[outColumnOffset + (r + 1) * verticalStride],
                                     checkedWrites);
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }
