__kernel void cl_fdwt53Kernel(__global int *input,
                              __global int *output,
                              const int sizeX,
                              const int sizeY,
                              const int winSteps,
                              const int WIN_SX,
                              const int WIN_SY)
{
    (void)winSteps;
    (void)WIN_SX;
    (void)WIN_SY;

    if (get_global_id(0) != 0 || get_global_id(1) != 0)
        return;

    const int lowW  = divRndUp_int(sizeX, 2);
    const int highW = sizeX / 2;
    const int lowH  = divRndUp_int(sizeY, 2);
    const int highH = sizeY / 2;

    const int llOffset = 0;
    const int hlOffset = lowW * lowH;
    const int lhOffset = hlOffset + highW * lowH;
    const int hhOffset = lhOffset + lowW * highH;


    for (int y = 0; y < sizeY; y++) {
        const int rowBase = y * sizeX;

        if (sizeX <= 1) {
            output[rowBase] = input[rowBase];
            continue;
        }

        const int h0 = forward53_high_row(input, rowBase, sizeX, 0);
        output[rowBase + lowW] = h0;
        output[rowBase] = input[rowBase] + ((h0 + h0 + 2) / 4);

        int hp = h0;
        for (int k = 1; k < highW; k++) {
            const int hc = forward53_high_row(input, rowBase, sizeX, k);
            output[rowBase + lowW + k] = hc;
            output[rowBase + k] = input[rowBase + 2 * k] + ((hp + hc + 2) / 4);
            hp = hc;
        }

        if (lowW > highW) {
            const int lastEvenIndex = 2 * (lowW - 1);
            output[rowBase + lowW - 1] =
                input[rowBase + lastEvenIndex] + ((hp + hp + 2) / 4);
        }
    }


    if (sizeY <= 1) {
        for (int x = 0; x < lowW; x++) {
            input[llOffset + x] = output[x];
        }
        for (int x = 0; x < highW; x++) {
            input[hlOffset + x] = output[lowW + x];
        }
    } else {

        for (int x = 0; x < lowW; x++) {
            const int h0 = forward53_high_col(output, x, sizeX, sizeY, 0);
            input[lhOffset + x] = h0;
            input[llOffset + x] = output[x] + ((h0 + h0 + 2) / 4);

            int hp = h0;
            for (int k = 1; k < highH; k++) {
                const int hc = forward53_high_col(output, x, sizeX, sizeY, k);
                input[lhOffset + k * lowW + x] = hc;
                input[llOffset + k * lowW + x] =
                    output[(2 * k) * sizeX + x] + ((hp + hc + 2) / 4);
                hp = hc;
            }

            if (lowH > highH) {
                const int lastEvenRow = 2 * (lowH - 1);
                input[llOffset + (lowH - 1) * lowW + x] =
                    output[lastEvenRow * sizeX + x] + ((hp + hp + 2) / 4);
            }
        }


        for (int x = 0; x < highW; x++) {
            const int col = lowW + x;
            const int h0 = forward53_high_col(output, col, sizeX, sizeY, 0);
            input[hhOffset + x] = h0;
            input[hlOffset + x] = output[col] + ((h0 + h0 + 2) / 4);

            int hp = h0;
            for (int k = 1; k < highH; k++) {
                const int hc = forward53_high_col(output, col, sizeX, sizeY, k);
                input[hhOffset + k * highW + x] = hc;
                input[hlOffset + k * highW + x] =
                    output[(2 * k) * sizeX + col] + ((hp + hc + 2) / 4);
                hp = hc;
            }

            if (lowH > highH) {
                const int lastEvenRow = 2 * (lowH - 1);
                input[hlOffset + (lowH - 1) * highW + x] =
                    output[lastEvenRow * sizeX + col] + ((hp + hp + 2) / 4);
            }
        }
    }


    const int total = sizeX * sizeY;
    for (int i = 0; i < total; i++) {
        output[i] = input[i];
    }
}

