		window--;

	RSComplex sigTfactors[4];
	calculate_sig_T(nuc, E, input, pseudo_K0RS, sigTfactors);

	Window w = windows[nuc * max_num_windows + window];
	sigT = E * w.T;
	sigA = E * w.A;
	sigF = E * w.F;

	for(int i = w.start; w.end > i; i++)
	{
		RSComplex PSIIKI;
		RSComplex CDUM;
		Pole pole = poles[nuc * max_num_poles + i];
		RSComplex t1 = {0.0, 1.0};
		RSComplex t2 = {sqrt(E), 0.0};
		PSIIKI = c_div(t1, c_sub(pole.MP_EA, t2));
		RSComplex E_c = {E, 0.0};
		CDUM = c_div(PSIIKI, E_c);
		sigT += c_mul(pole.MP_RT, c_mul(CDUM, sigTfactors[(int)pole.l_value])).r;
		sigA += c_mul(pole.MP_RA, CDUM).r;
		sigF += c_mul(pole.MP_RF, CDUM).r;
	}

	sigE = sigT - sigA;

	micro_xs[0] = sigT;
	micro_xs[1] = sigA;
	micro_xs[2] = sigF;
	micro_xs[3] = sigE;
}

inline void calculate_micro_xs_doppler(__private double * micro_xs,
                                       int nuc,
                                       double E,
                                       Input input,
                                       __global int * n_windows,
                                       __global double * pseudo_K0RS,
                                       __global Window * windows,
                                       __global Pole * poles,
                                       int max_num_windows,
                                       int max_num_poles)
{
	double sigT;
	double sigA;
	double sigF;
	double sigE;

	double spacing = 1.0 / (double)n_windows[nuc];
	int window = (int)(E / spacing);
	if(n_windows[nuc] == window)
		window--;

	RSComplex sigTfactors[4];
	calculate_sig_T(nuc, E, input, pseudo_K0RS, sigTfactors);

	Window w = windows[nuc * max_num_windows + window];
	sigT = E * w.T;
	sigA = E * w.A;
	sigF = E * w.F;

	double dopp = 0.5;

	for(int i = w.start; w.end > i; i++)
	{
		Pole pole = poles[nuc * max_num_poles + i];

		RSComplex E_c = {E, 0.0};
		RSComplex dopp_c = {dopp, 0.0};
		RSComplex Z = c_mul(c_sub(E_c, pole.MP_EA), dopp_c);

		RSComplex faddeeva = fast_nuclear_W(Z);

		sigT += c_mul(pole.MP_RT, c_mul(faddeeva, sigTfactors[(int)pole.l_value])).r;
		sigA += c_mul(pole.MP_RA, faddeeva).r;
		sigF += c_mul(pole.MP_RF, faddeeva).r;
	}

	sigE = sigT - sigA;

	micro_xs[0] = sigT;
	micro_xs[1] = sigA;
	micro_xs[2] = sigF;
	micro_xs[3] = sigE;
}

inline void calculate_macro_xs(__private double * macro_xs,
                               int mat,
                               double E,
                               Input input,
                               __global int * num_nucs,
                               __global int * mats,
                               int max_num_nucs,
                               __global double * concs,
                               __global int * n_windows,
                               __global double * pseudo_K0RS,
                               __global Window * windows,
                               __global Pole * poles,
                               int max_num_windows,
                               int max_num_poles)
{
	for(int i = 0; i < 4; i++)
		macro_xs[i] = 0.0;

	for(int i = 0; i < num_nucs[mat]; i++)
	{
		double micro_xs[4];
		int nuc = mats[mat * max_num_nucs + i];

		if(input.doppler == 1)
			calculate_micro_xs_doppler(micro_xs, nuc, E, input, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);
		else
			calculate_micro_xs(micro_xs, nuc, E, input, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);

		for(int j = 0; j < 4; j++)
			macro_xs[j] += micro_xs[j] * concs[mat * max_num_nucs + i];
	}
}

__kernel void macro_xs_lookup_kernel(Input in,
                                     __global int * num_nucs,
                                     __global int * mats,
                                     int max_num_nucs,
                                     __global double * concs,
                                     __global int * n_windows,
                                     __global double * pseudo_K0RS,
                                     __global Window * windows,
                                     __global Pole * poles,
                                     int max_num_windows,
                                     int max_num_poles,
                                     __global int * verification_array)
{
	const size_t i = get_global_id(0);

	if(i >= (size_t)in.lookups)
		return;

	ulong seed = STARTING_SEED;
	seed = fast_forward_LCG(seed, ((ulong)2) * (ulong)i);

	double E = LCG_random_double(&seed);
	int mat = pick_mat(&seed);

	double macro_xs[4] = {0.0, 0.0, 0.0, 0.0};

	calculate_macro_xs(macro_xs, mat, E, in, num_nucs, mats, max_num_nucs, concs, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);

	double max = -RS_DBL_MAX;
	int max_idx = 0;
	for(int x = 0; x < 4; x++)
	{
		if(max < macro_xs[x])
		{
			max = macro_xs[x];
			max_idx = x;
		}
	}

	verification_array[i] = max_idx + 1;
}

