		PSIIKI = c_div(t1, c_sub(pole.MP_EA, t2));
		RSComplex E_c = {E, 0.0};
		CDUM = c_div(PSIIKI, E_c);
		sigT = sigT + (c_mul(pole.MP_RT, c_mul(CDUM, sigTfactors[pole.l_value])).r);
		sigA = sigA + (c_mul(pole.MP_RA, CDUM).r);
		sigF = sigF + (c_mul(pole.MP_RF, CDUM).r);
